const body = $('Webhook Nova TD').first().json;

// Funcion segura para obtener items de un nodo
function safeGet(nodeName) {
  try { return $(nodeName).all().map(i=>i.json).filter(i=>!i.error); }
  catch(e) { return []; }
}

// 1. Historial del ticket
const historial = safeGet('1. Historial del ticket');
const historialTexto = historial.length
  ? historial.map(h=>`[${new Date(h.created_at).toLocaleDateString('es-CO')}] ${h.evento||''}: ${h.subject||''} ${h.from_email?'('+h.from_email+')':''}`).join('\n')
  : 'Sin historial previo';

// 2. Correos anteriores del remitente
const anteriores = safeGet('2. Correos anteriores del remitente');
const anterioresTexto = anteriores.length
  ? `Este remitente tiene ${anteriores.length} PQR anteriores:\n` + anteriores.map(c=>`- ${c.tipo_pqr||''}: ${c.resumen_corto||c.subject||''} [${c.estado}]`).join('\n')
  : 'Primer contacto del remitente';

// 3. Knowledge base
const kb = safeGet('3. Knowledge base ejemplos');
const kbTexto = kb.length
  ? `PLANTILLAS APROBADAS (usar como base y adaptar):\n` + kb.map((k,i)=>`Plantilla ${i+1} (situacion: ${k.situacion||'general'}, usada ${k.veces_usado} veces):\n${k.respuesta_modelo}`).join('\n\n')
  : '';

// 4. Casos similares
const similares = safeGet('4. Casos similares resueltos');
const similaresTexto = similares.length
  ? `CASOS SIMILARES RESUELTOS:\n` + similares.map((s,i)=>`Caso ${i+1}: ${s.resumen_corto||s.subject||''}`).join('\n')
  : '';

// 5. Hilo Graph
let hiloTexto = '';
try {
  const hiloRaw = $('5. Hilo completo Graph').first().json;
  const hiloMsgs = hiloRaw?.value || [];
  if (hiloMsgs.length > 1) {
    hiloTexto = `HILO DE CONVERSACION (${hiloMsgs.length} mensajes):\n` + hiloMsgs.map(m=>`[${m.receivedDateTime?.substring(0,10)||''}] ${m.from?.emailAddress?.name||''}: ${m.bodyPreview?.substring(0,200)||''}`).join('\n');
  }
} catch(e) { hiloTexto = ''; }

// Limpiar HTML del contenido
const contenidoLimpio = (body.body_content||'')
  .replace(/<[^>]+>/g,' ')
  .replace(/&nbsp;/g,' ')
  .replace(/&gt;/g,'>')
  .replace(/&lt;/g,'<')
  .replace(/\s+/g,' ')
  .trim()
  .substring(0,3000);

// Ensamblar contexto completo
const partes = [
  `=== INFORMACION DEL TICKET ===`,
  `Ticket ID: ${body.ticket_id||body.correo_id||''}`,
  `Asunto: ${body.asunto||body.subject||''}`,
  `Remitente: ${body.remitente_nombre||'Ciudadano'}`,
  `Agente asignado: ${body.agente_nombre||'Equipo PQRSFD'}`,
  `Tipo PQR: ${body.tipo_pqr||'No clasificado'}`,
  `Categoria: ${body.categoria_ia||''}`,
  `Prioridad: ${body.prioridad||'media'}`,
  `Urgente: ${body.es_urgente?'SI - ATENCION INMEDIATA REQUERIDA':'NO'}`,
  `Nivel riesgo: ${body.nivel_riesgo||'ninguno'}`,
  `Ley aplicable: ${body.ley_aplicable||'Ley 1755/2015'}`,
  `Fecha limite SLA: ${body.fecha_limite_sla||'No definida'}`,
  ``,
  `=== CONTENIDO DEL CORREO ===`,
  contenidoLimpio,
  ``,
  `=== HISTORIAL DE GESTIONES ===`,
  historialTexto,
  ``,
  `=== PERFIL DEL REMITENTE ===`,
  anterioresTexto
];

if (hiloTexto) { partes.push(''); partes.push(hiloTexto); }
if (kbTexto) { partes.push(''); partes.push(kbTexto); }
if (similaresTexto) { partes.push(''); partes.push(similaresTexto); }

const contexto = partes.join('\n');

return [{ json: { contexto, ...body, _kb_disponible: kb.length > 0, _hilo_disponible: hiloTexto.length > 0 } }];

const body = $('Webhook Nova TD').first().json;
const ensamblado = $('Ensamblar contexto enriquecido').first().json;
const raw = $input.first().json.choices?.[0]?.message?.content || $input.first().json.message?.content || '';
const respuesta_html = raw.replace(/```html|```/g,'').trim();

let confianza = 65;
const advertencias = [];

// Bonus por fuentes
if (ensamblado._kb_disponible) confianza += 20;
if (ensamblado._hilo_disponible) confianza += 5;
if (body.body_content && body.body_content.length > 200) confianza += 5;
if (body.tipo_pqr) confianza += 5;

// Penalizaciones
if (!body.body_content || body.body_content.length < 50) {
  confianza -= 20;
  advertencias.push('Contenido del correo muy corto');
}
if (body.es_urgente) {
  const tieneUrgencia = ['urgent','inmediata','priorit','horas','vital','critico'].some(w=>respuesta_html.toLowerCase().includes(w));
  if (!tieneUrgencia) {
    advertencias.push('Ticket urgente — verifica que la respuesta refleje la urgencia');
    confianza -= 15;
  }
}
if (respuesta_html.length < 300) {
  confianza -= 15;
  advertencias.push('Respuesta muy corta — considera ampliarla');
}
if (!respuesta_html.includes('pqrsfd@tododrogas.com.co')) {
  advertencias.push('Falta el correo de contacto');
  confianza -= 5;
}

confianza = Math.max(10, Math.min(100, confianza));

return [{ json: {
  respuesta_html,
  confianza,
  advertencias,
  ticket_id: body.ticket_id || body.correo_id || '',
  generado_en: new Date().toISOString(),
  fuentes_usadas: {
    kb: ensamblado._kb_disponible,
    historial: true,
    perfil_remitente: true,
    hilo_graph: ensamblado._hilo_disponible
  }
} }];
